import{_ as s,o as i,c as a,a5 as t}from"./chunks/framework.De5lvF_N.js";const k=JSON.parse('{"title":"Bootstrap a provider","description":"","frontmatter":{"title":"Bootstrap a provider","personas":["service-provider"]},"headers":[],"relativePath":"how-to-guides/bootstrap-provider.md","filePath":"how-to-guides/bootstrap-provider.md"}'),r={name:"how-to-guides/bootstrap-provider.md"};function o(p,e,n,h,l,d){return i(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="bootstrap-a-provider" tabindex="-1">Bootstrap a provider <a class="header-anchor" href="#bootstrap-a-provider" aria-label="Permalink to &quot;Bootstrap a provider&quot;">​</a></h1><p>Use this how-to to provision a dedicated kcp workspace for your service by creating a <code>Provider</code> resource. The workspace is your provider&#39;s domain on the platform — once it is ready, you use the issued kubeconfig to bootstrap your service APIs, register your provider in the marketplace, and wire your controllers into the workspace.</p><h2 id="when-to-use-this" tabindex="-1">When to use this <a class="header-anchor" href="#when-to-use-this" aria-label="Permalink to &quot;When to use this&quot;">​</a></h2><p>Use this guide when your team operates a service independently and manages its own provider workspace. If the platform team owns the service end-to-end, use <a href="./onboard-managed-service.html">Onboard a managed service</a> instead.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li><code>kubectl</code> access to a kcp workspace that has an <code>APIBinding</code> to the <code>providers.platform-mesh.io</code> export from <code>root:platform-mesh-system</code></li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The workflow for obtaining this binding — the provider onboarding path — is not yet documented. For now, a platform owner must create the binding manually in the target workspace. This guide will be updated when the onboarding workflow is defined.</p></div><h2 id="step-1-create-the-provider-resource" tabindex="-1">Step 1: Create the Provider resource <a class="header-anchor" href="#step-1-create-the-provider-resource" aria-label="Permalink to &quot;Step 1: Create the Provider resource&quot;">​</a></h2><p>Apply a <code>Provider</code> in the workspace where you have the <code>providers.platform-mesh.io</code> binding. All spec fields are optional — a minimal resource has an empty spec:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">apiVersion</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">providers.platform-mesh.io/v1alpha1</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">kind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Provider</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">metadata</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">my-service</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">spec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {}</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apply</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> provider.yaml</span></span></code></pre></div><h2 id="step-2-wait-for-the-workspace-to-be-ready" tabindex="-1">Step 2: Wait for the workspace to be ready <a class="header-anchor" href="#step-2-wait-for-the-workspace-to-be-ready" aria-label="Permalink to &quot;Step 2: Wait for the workspace to be ready&quot;">​</a></h2><p>The Provider controller provisions a workspace and kubeconfig. Watch the phase:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> provider</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-service</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -w</span></span></code></pre></div><p>Expected output once provisioning completes:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NAME         PHASE   READY</span></span>
<span class="line"><span>my-service   Ready   True</span></span></code></pre></div><h2 id="step-3-retrieve-the-kubeconfig" tabindex="-1">Step 3: Retrieve the kubeconfig <a class="header-anchor" href="#step-3-retrieve-the-kubeconfig" aria-label="Permalink to &quot;Step 3: Retrieve the kubeconfig&quot;">​</a></h2><p>The controller writes a kubeconfig Secret into the workspace where the <code>Provider</code> lives. Retrieve it:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> secret</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-service-provider-kubeconfig</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> default</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jsonpath=&#39;{.data.kubeconfig}&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> base64</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> provider-kubeconfig.yaml</span></span></code></pre></div><p>Use this kubeconfig to authenticate against the provider workspace in kcp.</p><h2 id="step-4-bootstrap-workspace-resources" tabindex="-1">Step 4: Bootstrap workspace resources <a class="header-anchor" href="#step-4-bootstrap-workspace-resources" aria-label="Permalink to &quot;Step 4: Bootstrap workspace resources&quot;">​</a></h2><p>Use the kubeconfig to seed the provider workspace with the resources your service needs to run and expose itself — for example, <code>APIExport</code>, <code>APIResourceSchema</code>, <code>ContentConfiguration</code>, <code>ProviderMetadata</code>, and RBAC. The kubeconfig can be passed to any mechanism that applies Kubernetes resources: an init container in the operator deployment, a dedicated setup controller, a GitOps pipeline, or similar.</p><p>Applying resources manually is possible but not the intended long-term approach:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> PROVIDER_KUBECONFIG</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">provider-kubeconfig.yaml</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --kubeconfig</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $PROVIDER_KUBECONFIG </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">apply</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">your-workspace-resource</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">s</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><h2 id="step-5-wire-the-kubeconfig-into-your-service-controllers" tabindex="-1">Step 5: Wire the kubeconfig into your service controllers <a class="header-anchor" href="#step-5-wire-the-kubeconfig-into-your-service-controllers" aria-label="Permalink to &quot;Step 5: Wire the kubeconfig into your service controllers&quot;">​</a></h2><p>Configure your service controllers to use the provider kubeconfig to watch the <code>APIExport</code> virtual workspace and reconcile service consumers. See <a href="/pr-preview/pr-235/concepts/integration-paths.html">Integration paths</a> to choose the right mechanism and find the corresponding tutorial.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-235/reference/resources/provider-resource.html">Provider resource</a></li><li><a href="/pr-preview/pr-235/concepts/provider-bootstrap.html">Provider bootstrap</a></li><li><a href="/pr-preview/pr-235/concepts/integration-paths.html">Integration paths</a></li><li><a href="/pr-preview/pr-235/concepts/personas/service-provider.html">Service provider persona</a></li></ul>`,28)])])}const u=s(r,[["render",o]]);export{k as __pageData,u as default};
